<?php
declare(strict_types=1);
require_once __DIR__ . '/includes/auth.php';
require_once __DIR__ . '/admin/includes/documents_helpers.php';
require_once __DIR__ . '/includes/customer_document_acceptance.php';
require_once __DIR__ . '/includes/commercial_lifecycle.php';
require_admin();documents_ensure_structure();
$redirect=function(string $msg,string $status='success'): void {header('Location: admin-challans.php?'.http_build_query(['message'=>$msg,'status'=>$status]));exit;};
if($_SERVER['REQUEST_METHOD']==='POST'){
 if(!verify_csrf_token($_POST['csrf_token']??null))$redirect('Security validation failed.','error');
 $action=safe_text($_POST['action']??'');
 $id=safe_text($_POST['id']??'');
 if($action==='create_from_dispatch_advice'){
  $d=documents_get_dispatch_advice($id); if(!$d)$redirect('Dispatch Advice not found.','error');
  $r=documents_create_challan_from_accepted_dispatch_advice($d,current_user()?:['role'=>'admin','name'=>'Admin']);
  if(empty($r['ok']))$redirect((string)($r['error']??'Unable to create Challan.'),'error');
  header('Location: challan-view.php?id='.urlencode((string)$r['challan']['id']).'&message='.urlencode(!empty($r['created'])?'Challan created.':'Existing Challan opened.').'&status=success');exit;
 }
 $redirect('Invalid action.','error');
}
$tab=safe_text($_GET['tab']??'accepted');$allowed=['accepted','created','dispatched','delivered','archived_cancelled','legacy'];if(!in_array($tab,$allowed,true))$tab='accepted';
$advices=documents_list_dispatch_advices();$workflowRows=[];$counts=array_fill_keys($allowed,0);
foreach($advices as $d){$arch=in_array(strtolower((string)($d['status']??'')),['archived','cancelled','superseded'],true)||!empty($d['archived_flag']);$eligible=documents_dispatch_advice_challan_eligible($d);$c=documents_challan_for_dispatch_advice((string)($d['id']??''));$wf=documents_challan_workflow_status($d,$c);$bucket=$arch?'archived_cancelled':strtolower($wf);if($eligible||$arch||$c){$workflowRows[]=['advice'=>$d,'challan'=>$c,'workflow'=>$wf,'bucket'=>$bucket];$counts[$bucket]=($counts[$bucket]??0)+1;}}
$legacy=array_values(array_filter(documents_list_challans(),static fn($c)=>safe_text((string)($c['dispatch_advice_id']??''))===''));
$counts['legacy']=count($legacy);
$visible=array_values(array_filter($workflowRows,static fn($r)=>$GLOBALS['tab']==='accepted' ? !in_array($r['bucket'],['archived_cancelled'],true) : $r['bucket']===$GLOBALS['tab']));
usort($visible,static fn($a,$b)=>strcmp((string)($b['advice']['accepted_at']??$b['advice']['acknowledged_at']??$b['advice']['created_at']??''),(string)($a['advice']['accepted_at']??$a['advice']['acknowledged_at']??$a['advice']['created_at']??'')));
function h($v): string {return htmlspecialchars((string)$v,ENT_QUOTES,'UTF-8');}
?><!doctype html><html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>Admin Challans</title><link rel="stylesheet" href="assets/css/admin-unified.css"></head><body class="admin-shell commercial-admin"><main class="commercial-shell">
<header class="card commercial-header"><div><p class="admin-kicker">Commercial workspace</p><h1>Delivery Challans</h1><p>Create Challans only from customer-accepted Dispatch Advices, then track dispatch and customer delivery confirmation.</p></div><nav class="commercial-header__actions"><a class="btn secondary" href="admin-dashboard.php">Dashboard</a><a class="btn secondary" href="admin-documents.php">Document Center</a></nav></header><?= render_commercial_lifecycle('challan') ?>
<?php if(isset($_GET['message'])):?><div class="card" style="background:<?=h(($_GET['status']??'')==='error'?'#fef2f2':'#ecfdf5')?>"><?=h($_GET['message'])?></div><?php endif;?>
<nav class="workspace-tabs" aria-label="Challan tabs"><?php foreach(['accepted'=>'Accepted Dispatch Advices','created'=>'Created','dispatched'=>'Dispatched','delivered'=>'Delivered','archived_cancelled'=>'Archived / Cancelled','legacy'=>'Legacy / Manual Challan'] as $key=>$label):?><a class="<?=$tab===$key?'active':''?>" href="?tab=<?=h($key)?>"><?=h($label)?> <span class="muted-helper">(<?= (int)($counts[$key]??0) ?>)</span></a><?php endforeach;?></nav>
<?php if($tab==='legacy'):?><section class="card"><h2>Legacy / Manual Challans</h2><p class="muted-helper">Standalone Challans remain accessible for backward compatibility, but new routine work starts from accepted Dispatch Advices.</p><table><thead><tr><th>Challan</th><th>Customer</th><th>Status</th><th>Delivery Date</th><th>Actions</th></tr></thead><tbody><?php foreach($legacy as $c):?><tr><td><strong><?=h($c['challan_no']??$c['dc_number']??'')?></strong></td><td><?=h($c['customer_snapshot']['name']??'')?><br><span class="muted-helper"><?=h($c['customer_snapshot']['mobile']??'')?></span></td><td><span class="status-badge"><?=h($c['status']??'')?></span></td><td><?=h($c['delivery_date']??'')?></td><td><a class="btn" href="challan-view.php?id=<?=urlencode((string)$c['id'])?>">Open</a></td></tr><?php endforeach;if(!$legacy):?><tr><td colspan="5" class="empty-state">No legacy Challans.</td></tr><?php endif;?></tbody></table></section><?php else:?><section class="card"><div class="commercial-toolbar"><div><h2><?=h(['accepted'=>'Accepted Dispatch Advice workspace','created'=>'Created Challans','dispatched'=>'Dispatched Challans','delivered'=>'Delivered Challans','archived_cancelled'=>'Archived / Cancelled'][$tab])?></h2><p class="muted-helper">Pending rows have no linked Challan. Created rows are ready for operational details and Mark Dispatched.</p></div></div><div class="responsive-table"><table><thead><tr><th>Dispatch Advice</th><th>Customer</th><th>Quotation</th><th>Planned Dispatch Date</th><th>Materials</th><th>Challan Status</th><th>Challan Number</th><th>Actions</th></tr></thead><tbody><?php foreach($visible as $row):$d=$row['advice'];$c=$row['challan'];$wf=$row['workflow'];$e=(array)($c['customer_acceptance']??[]);?><tr><td><strong><?=h($d['dispatch_advice_no']??'')?></strong><br><span class="muted-helper">Accepted: <?=h($d['customer_acceptance']['confirmed_at']??$d['acknowledged_at']??$d['accepted_at']??'')?></span></td><td><?=h($d['customer_name']??'')?><br><span class="muted-helper"><?=h(customer_acceptance_mask_mobile((string)($d['customer_mobile']??'')))?></span></td><td><?=h($d['quotation_no']??'')?></td><td><?=h($d['planned_dispatch_date']??'')?></td><td><?=count((array)($d['items']??[]))?> item(s)</td><td><span class="status-badge status-badge--<?=strtolower($wf)?>"><?=h($wf)?></span><?php if($wf==='Delivered'):?><br><span class="muted-helper"><?=h($e['confirmed_at']??$c['delivered_at']??'')?> · <?=h($e['acceptance_ref']??'')?></span><?php if(!empty($c['delivery_issue_flag'])):?><br><span class="status-badge status-badge--warning">Delivery issue reported</span><?php endif;endif;?></td><td><?=h($c['challan_no']??$c['dc_number']??'—')?></td><td><div class="row-action-group"><?php if(!$c):?><form method="post"><input type="hidden" name="csrf_token" value="<?=h($_SESSION['csrf_token']??'')?>"><input type="hidden" name="id" value="<?=h($d['id'])?>"><button class="btn" name="action" value="create_from_dispatch_advice">Create Challan</button></form><?php else:?><a class="btn" href="challan-view.php?id=<?=urlencode((string)$c['id'])?>">Open Challan</a><?php if($wf==='Dispatched'):?><a class="btn secondary" href="challan-public.php?token=<?=urlencode((string)($c['public_token']??''))?>" target="_blank" rel="noopener">Copy Link</a><?php endif;endif;?></div></td></tr><?php endforeach;if(!$visible):?><tr><td colspan="8" class="empty-state">No records in this tab.</td></tr><?php endif;?></tbody></table></div></section><?php endif;?></main></body></html>
